// Log the discovery result. All scoring/dedup logic ran inside the function.
// This node only logs — it does not re-implement any business logic.
// Hardened: wraps all parsing in try/catch to prevent 'Unknown error' crashes
// from HTML error pages, gateway timeouts, or malformed responses.
try {
  const res = $input.first();
  const status = res.json?.statusCode || res.json?.status || 200;

  // Detect HTML / non-JSON body (e.g. 504 gateway timeout page)
  const rawBody = res.json?.body;
  let body = {};
  if (typeof rawBody === 'string') {
    const trimmed = rawBody.trim();
    if (trimmed.startsWith('<') || trimmed === '') {
      console.error('[discovery] Non-JSON response body — likely gateway timeout or proxy error. Status:', status, 'Preview:', trimmed.slice(0, 120));
      return [{ json: { ok: false, error: 'non_json_response', status, raw_preview: trimmed.slice(0, 200) } }];
    }
    try {
      body = JSON.parse(trimmed);
    } catch (parseErr) {
      console.error('[discovery] Failed to parse response body as JSON. Status:', status, 'Preview:', trimmed.slice(0, 120));
      return [{ json: { ok: false, error: 'json_parse_error', status, raw_preview: trimmed.slice(0, 200) } }];
    }
  } else if (rawBody !== null && rawBody !== undefined) {
    body = rawBody;
  } else {
    body = res.json || {};
  }

  if (status === 401) {
    console.error('[discovery] UNAUTHORIZED — check DISCOVERY_SECRET env var in n8n and Netlify');
    return [{ json: { ok: false, error: 'unauthorized', status } }];
  }

  if (status === 403) {
    console.error('[discovery] FORBIDDEN — check DISCOVERY_SECRET env var or IP allowlist');
    return [{ json: { ok: false, error: 'forbidden', status } }];
  }

  if (status === 500) {
    console.error('[discovery] Server error from /discover. Message:', body.message || body.error || '(none)');
    return [{ json: { ok: false, error: 'server_error', status, message: body.message || body.error || 'internal server error' } }];
  }

  if (status === 504 || status === 502 || status === 503) {
    console.error('[discovery] Gateway timeout or service unavailable. Status:', status);
    return [{ json: { ok: false, error: 'gateway_timeout', status } }];
  }

  if (status !== 200 || body.ok === false) {
    console.warn('[discovery] Run skipped or failed:', body.message || body.error || JSON.stringify(body));
    return [{ json: { ok: false, message: body.message || body.error, status } }];
  }

  if (body.mode === 'demo') {
    console.log('[discovery] Demo mode — no real discovery ran.');
    return [{ json: { ok: true, mode: 'demo' } }];
  }

  console.log(
    `[discovery] Run complete: ${body.sources_run} source(s), ` +
    `${body.total_discovered} discovered, ${body.total_ingested} ingested`
  );

  return [{ json: body }];
} catch (err) {
  console.error('[discovery] Unexpected error in Log Discovery Result node:', err.message || String(err));
  return [{ json: { ok: false, error: 'node_error', message: err.message || String(err) } }];
}

// Forward the discovery_run_complete event summary to webhooks.
// Hardened: wraps in try/catch to avoid 'Unknown error' crashes on bad upstream data.
try {
  const body = $input.first()?.json || {};
  return [{ json: {
    event: 'discovery_run_complete',
    payload: {
      sources_run: body.sources_run || 0,
      total_discovered: body.total_discovered || 0,
      total_ingested: body.total_ingested || 0,
      timestamp: new Date().toISOString()
    }
  }}];
} catch (err) {
  console.error('[discovery] Build Event Payload error:', err.message || String(err));
  return [{ json: { event: 'discovery_run_complete', payload: { error: err.message || String(err), timestamp: new Date().toISOString() } } }];
}
